@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadMessages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private int activeChannelId;
    private string activeChannelName = "";
    private string activeChannelDescription = "";

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private int? threadRootMessageId;

    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        var channel = channels.First(c => c.Id == channelId);
        activeChannelName = channel.Name;
        activeChannelDescription = channel.Description;
        hasMoreMessages = true;

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channels to update unread counts
        channels = await ChatService.GetChannelsAsync();

        // Build thread summaries from messages that have replies
        await BuildThreadSummaries();

        CloseThreadSync();
    }

    private async Task BuildThreadSummaries()
    {
        threadSummaries.Clear();
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        // Count replies referencing root messages in the current set
        foreach (var msg in messages.Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value)))
