+        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+        await ChatService.MarkChannelReadAsync(channelId);
+
+        // Refresh channels to update unread counts
+        channels = await ChatService.GetChannelsAsync();
+
+        // Build thread summaries from messages that have replies
+        await BuildThreadSummaries();
+
+        CloseThreadSync();
+    }
+
+    private async Task BuildThreadSummaries()
+    {
+        threadSummaries.Clear();
+        var rootIds = messages
+            .Where(m => m.ReplyToId is null)
+            .Select(m => m.Id)
+            .ToHashSet();
+
+        // Count replies referencing root messages in the current set
+        foreach (var msg in messages.Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value)))
+        {
+            var rootId = msg.ReplyToId!.Value;
+            if (!threadSummaries.ContainsKey(rootId))
+            {
+                // Fetch the full thread to get accurate counts
+                var thread = await ChatService.GetThreadAsync(rootId);
+                threadSummaries[rootId] = new ThreadSummary(
+                    rootId,
+                    thread.Count,
+                    thread.Count > 0 ? thread.Max(t => t.SentAt) : DateTime.UtcNow);
+            }
+        }
+    }
+
+    private async Task LoadMoreMessages()
+    {
+        if (isLoadingMore || !hasMoreMessages) return;
+        isLoadingMore = true;
+
+        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
+        if (older.Count < PageSize)
+        {
+            hasMoreMessages = false;
+        }
+
+        messages.InsertRange(0, older);
+        isLoadingMore = false;
+    }
+
+    private async Task SendMessage(string content)
+    {
+        var sent = await ChatService.SendMessageAsync(activeChannelId, content, null);
+        messages.Add(sent);
+    }
+
+    private async Task OpenThread(int rootMessageId)
+    {
+        threadRootMessageId = rootMessageId;
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
+        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
+        isThreadOpen = true;
+    }
+
+    private void CloseThreadSync()
+    {
+        isThreadOpen = false;
+        threadRootMessage = null;
+        threadRootMessageId = null;
+        threadMessages = [];
+    }
+
+    private async Task CloseThread()
+    {
+        CloseThreadSync();
+        await Task.CompletedTask;
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (threadRootMessageId is null) return;
+        var reply = await ChatService.SendMessageAsync(activeChannelId, content, threadRootMessageId);
+        threadMessages.Add(reply);
+
+        // Update thread summary count
+        if (threadSummaries.TryGetValue(threadRootMessageId.Value, out var existing))
+        {
+            threadSummaries[threadRootMessageId.Value] = existing with { ReplyCount = existing.ReplyCount + 1, LastReplyAt = reply.SentAt };
+        }
+        else
+        {
+            threadSummaries[threadRootMessageId.Value] = new ThreadSummary(threadRootMessageId.Value, 1, reply.SentAt);
+        }
+    }
+
+    private async Task HandleReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+        // Refresh messages to reflect updated reactions
+        messages = await ChatService.GetMessagesAsync(activeChannelId, 0, messages.Count);
+    }
+}
